package com.example;

public class Solution {
    /**
     * Tính tổng của hai số nguyên
     * @param a Số thứ nhất
     * @param b Số thứ hai
     * @return Tổng của a và b
     */
    public int tinhTong(int a, int b) {
        return a + b;
    }

    /**
     * Tính tích của hai số nguyên
     * @param a Số thứ nhất
     * @param b Số thứ hai
     * @return Tích của a và b
     */
    public int tinhTich(int a, int b) {
        return a * b;
    }

    /**
     * Kiểm tra số có phải số chẵn không
     * @param n Số cần kiểm tra
     * @return true nếu n là số chẵn, false nếu n là số lẻ
     */
    public boolean lasoChang(int n) {
        return n % 2 == 0;
    }
}
